scripts.script:
// A deterministic daily time series (no randomness, so the demo is stable).
// Enough points that a pinch/pan actually has somewhere to go.
function momentumSeries() {
  var out = []
  var start = new Date('2023-01-01').getTime()
  var day = 86400000
  var v = 120
  for (var i = 0; i < 220; i++) {
    // smooth composite drift: a couple of sines plus a slow trend
    v =
      120 +
      38 * Math.sin(i / 13) +
      18 * Math.sin(i / 4.5) +
      i * 0.32
    out.push([start + i * day, Math.round(v * 100) / 100])
  }
  return out
}

chart.options:
chart: {
  id: 'momentumChart',
  height: 400,
  type: 'area',
  fontFamily: 'Helvetica, Arial, sans-serif',
  animations: { enabled: false },
  toolbar: {
    autoSelected: 'pan',
    tools: { pan: true, zoom: true, zoomin: true, zoomout: true, reset: true, download: false },
  },
  zoom: {
    enabled: true,
    type: 'x',
    pinch: true,
  },
  pan: {
    inertia: true,
    friction: 0.92,
  },
},
colors: ['#4f46e5'],
dataLabels: { enabled: false },
stroke: { curve: 'smooth', width: 2 },
fill: {
  type: 'gradient',
  gradient: { shadeIntensity: 0.3, opacityFrom: 0.35, opacityTo: 0.03, stops: [0, 100] },
},
title: { text: 'Sensor reading (220 days)', align: 'left' },
subtitle: { text: 'Pinch to zoom, two-finger pan, flick to glide', align: 'left' },
xaxis: {
  type: 'datetime',
},
yaxis: {
  labels: { formatter: function (v) { return Math.round(v) } },
},
tooltip: { x: { format: 'dd MMM yyyy' } },

vanilla-js-script:
var gestureEl = document.getElementById('gesture')
var windowEl = document.getElementById('window')

function fmt(ts) {
  var d = new Date(ts)
  return d.toISOString().slice(0, 10)
}
function showWindow(label, xaxis) {
  gestureEl.innerHTML = label
  if (xaxis && xaxis.min != null && xaxis.max != null) {
    windowEl.innerHTML = fmt(xaxis.min) + '  to  ' + fmt(xaxis.max)
  }
}

// zoomed fires at the end of a pinch (and on wheel / toolbar zoom); scrolled
// fires continuously while panning and once the inertia glide comes to rest.
chart.addEventListener('zoomed', function (c, opts) {
  showWindow('zoomed', opts.xaxis)
})
chart.addEventListener('scrolled', function (c, opts) {
  showWindow('panned', opts.xaxis)
})

react-script:
React.useEffect(() => {
  // The react-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id. Poll until it exists, then wire the same readout the vanilla
  // build does. (momentumSeries lives in the shared head script.)
  let chart
  const timer = window.setInterval(() => {
    chart = ApexCharts.getChartByID('momentumChart')
    if (!chart) return
    window.clearInterval(timer)

    const gestureEl = document.getElementById('gesture')
    const windowEl = document.getElementById('window')

    const fmt = (ts) => new Date(ts).toISOString().slice(0, 10)
    const showWindow = (label, xaxis) => {
      gestureEl.innerHTML = label
      if (xaxis && xaxis.min != null && xaxis.max != null) {
        windowEl.innerHTML = fmt(xaxis.min) + '  to  ' + fmt(xaxis.max)
      }
    }

    // zoomed fires at the end of a pinch (and on wheel / toolbar zoom); scrolled
    // fires continuously while panning and once the inertia glide comes to rest.
    chart.addEventListener('zoomed', (c, opts) => showWindow('zoomed', opts.xaxis))
    chart.addEventListener('scrolled', (c, opts) => showWindow('panned', opts.xaxis))
  }, 50)

  return () => {
    window.clearInterval(timer)
  }
}, [])

vue-script:
mounted: function () {
  // The vue-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id. Poll until it exists, then wire the same readout the vanilla
  // build does. (momentumSeries lives in the shared head script.)
  var timer = window.setInterval(function () {
    var chart = ApexCharts.getChartByID('momentumChart')
    if (!chart) return
    window.clearInterval(timer)

    var gestureEl = document.getElementById('gesture')
    var windowEl = document.getElementById('window')

    function fmt(ts) {
      return new Date(ts).toISOString().slice(0, 10)
    }
    function showWindow(label, xaxis) {
      gestureEl.innerHTML = label
      if (xaxis && xaxis.min != null && xaxis.max != null) {
        windowEl.innerHTML = fmt(xaxis.min) + '  to  ' + fmt(xaxis.max)
      }
    }

    // zoomed fires at the end of a pinch (and on wheel / toolbar zoom); scrolled
    // fires continuously while panning and once the inertia glide comes to rest.
    chart.addEventListener('zoomed', function (c, opts) {
      showWindow('zoomed', opts.xaxis)
    })
    chart.addEventListener('scrolled', function (c, opts) {
      showWindow('panned', opts.xaxis)
    })
  }, 50)
},
